INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_B', 'D7', 4, 'B', 'Generalization', NULL, 'Ask: ''Make up a trick to help a younger kid remember which math signs let you swap the numbers around.''', 'Creates a memory aid distinguishing + and x from - and ÷.', 'Is confused about which operations allow swapping.', 'Why are + and x ''friendly'' to swapping, but - and ÷ aren''t?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_C', 'D7', 4, 'C', 'Generalization', NULL, 'Say: ''Show me why adding zero to a number never changes it, but multiplying a number by zero changes it to zero.''', 'Explains that adding zero means putting nothing in the pile. Multiplying by zero means having NO piles.', 'Mixes up the rules for zero.', 'What is the ''magic number'' you multiply by to keep a number the same? (Identity property of multiplication = 1).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_A', 'D8', 1, 'A', 'Physical balance', 'A hanger balance or visual balance scale, identical items', 'Put 4 identical blocks on the left, 4 on the right. It balances. Add 1 block to the left. Ask: ''What do I have to do to the right to make it balance again?''', 'Understands that whatever happens to one side must happen to the other.', 'Takes a block away from the right.', 'Why does the equal sign mean ''balance'' and not just ''here comes the answer''?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_B', 'D8', 1, 'B', 'Physical balance', 'Two transparent cups, water', 'Pour water into two cups so they are exactly even. Say: ''These are equal.'' Take a sip from one cup. Ask: ''Are they still equal? How do I make them equal again?''', 'Says you must take the same size sip from the other cup.', 'Suggests adding water to the first cup (this is correct, but doesn''t show equivalence of action).', 'If I do something to the left side, what is the golden rule for the right side?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L1_C', 'D8', 1, 'C', 'Physical balance', 'Scale, different sized objects', 'Put a heavy object on the left. Put 5 light objects on the right so it balances. Ask: ''Is 1 heavy thing equal to 5 light things?''', 'Understands that 1 can equal 5 if the total weight is the same.', 'Says it''s not equal because 1 is not the number 5.', 'Can a big number like 10 be equal to a bunch of small numbers? How?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_A', 'D8', 2, 'A', 'Symbolic balance', NULL, 'Write 5 + 4 = 6 + ___. Remind them: ''='' means BALANCE, not ''write the answer here''.', 'Finds the missing number (3) without adding all visible numbers together.', 'Writes 9 or 15 in the blank.', 'How did you figure out the blank without just guessing?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_B', 'D8', 2, 'B', 'Symbolic balance', NULL, 'Write 10 = ___ + 4. Ask them to solve it.', 'Understands that the equation can be ''backwards''. Blank is 6.', 'Gets confused because the answer is on the left.', 'Does the = sign care which side the math problem is on?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L2_C', 'D8', 2, 'C', 'Symbolic balance', NULL, 'Ask: ''Is this true or false? 4 + 4 = 4 + 4''', 'Recognizes it is true because both sides are identical.', 'Says it''s false because there''s no single answer.', 'What about 4 + 4 = 8 + 0? Is that true?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_A', 'D8', 3, 'A', 'Error detection', NULL, 'Show this: 8 + 4 = 12 + 2 = 14. Ask: ''Your friend wrote this. What did they think the ''='' sign meant? How would you explain they are wrong?''', 'Understands the friend thought ''='' meant ''compute'', creating a run-on equation (8+4 != 14). Fixes it by separating into two equations.', 'Doesn''t see the problem because 12+2 is 14.', 'Can you ever have two ''='' signs in a row like that if the ends don''t match?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_B', 'D8', 3, 'B', 'Error detection', NULL, 'Say: ''A student saw 7 + 5 = ___ + 4. They wrote 12 in the blank. Why did they write 12?''', 'Explains that the student just added 7 and 5 and ignored the ''+ 4''.', 'Thinks 12 is correct.', 'If we put 12 in the blank, what is the total on the right side? Does 12 balance 16?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L3_C', 'D8', 3, 'C', 'Error detection', NULL, 'Show: ___ = 5 + 3. ''Someone says you can''t start with a blank. Are they right?''', 'Explains that an equation is a balance, so you can start with the total.', 'Agrees you can''t start with a blank.', 'If a scale balances, does it matter which side you look at first?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_A', 'D8', 4, 'A', 'Design', NULL, 'Ask: ''Create the longest balancing equation you can using addition and subtraction. Like 5 + 5 = 12 - 2 = 6 + 4.''', 'Creates a true, multi-term equation demonstrating deep understanding of equivalence.', 'Makes calculation errors or creates a run-on equation.', 'How can you check every part of your long equation to make sure it''s perfect?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_B', 'D8', 4, 'B', 'Design', NULL, 'Ask: ''Write an equation where the answer is 20, but the number 20 is not allowed to be written anywhere.''', 'Writes something like 10 + 10 = 15 + 5.', 'Cannot conceptualize an equation without the final answer written.', 'Why don''t you need to write the answer to show that they are equal?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_C', 'D8', 4, 'C', 'Design', NULL, 'Say: ''Make a puzzle for me like 7 + ___ = 10 + 2. Don''t make it too easy!''', 'Sets up an equivalent expression with one missing variable.', 'Sets up a standard 7 + 2 = ___ problem.', 'What happens if I guess a number that is too big for your puzzle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_A', 'D9', 1, 'A', 'Magnitude guessing', 'A clear jar with items (e.g., beans)', 'Show the jar. Ask: ''Are there about 10, about 100, or about 1000 in here? Why do you think that?''', 'Picks the right order of magnitude without counting.', 'Insists on opening the jar to count exactly.', 'How does looking at the size of one bean help you guess the total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_B', 'D9', 1, 'B', 'Magnitude guessing', 'A book', 'Show a thick book. Ask: ''Does this book have about 20 pages, 200 pages, or 2000 pages? Don''t open it.''', 'Guesses reasonably based on thickness.', 'Cannot connect thickness to quantity.', 'If a book had 2000 pages, how heavy would it be?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L1_C', 'D9', 1, 'C', 'Magnitude guessing', 'Outdoors or looking out a window', 'Point to a large tree. Ask: ''Does that tree have about 50 leaves, 500 leaves, or more than 5000 leaves?''', 'Understands that natural objects often exist in very large, uncountable quantities.', 'Guesses a small number like 50.', 'Why is it impossible to know the exact number? Does it matter?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_A', 'D9', 2, 'A', 'Rounding basics', NULL, 'Ask: ''Is 48 closer to 40 or 50?''', 'Identifies 50 because 8 is closer to the next ten.', 'Guesses randomly.', 'Is your estimate a guess, or did you use a strategy? What''s the difference?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_B', 'D9', 2, 'B', 'Rounding basics', NULL, 'Say: ''I have 52 coins. My friend has 39 coins. About how many do we have together: 80, 90, or 100?''', 'Rounds 52 to 50, 39 to 40. 50+40 = 90.', 'Tries to calculate 52+39 exactly and gets lost.', 'Why is 90 a good enough answer for this question?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L2_C', 'D9', 2, 'C', 'Rounding basics', NULL, 'Ask: ''If you take 19 away from 82, will the answer be in the 50s, 60s, or 70s?''', 'Uses estimation (80 - 20 = 60) to find the right decade.', 'Calculates exactly.', 'How does knowing the ''tens'' help you check your exact answer later?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_A', 'D9', 3, 'A', 'Checking calculations', NULL, 'Say: ''Someone added 42 + 59 and got 81. Before adding it yourself, how do you know their answer MUST be wrong?''', 'Notes that 40 + 50 is 90, so the answer must be bigger than 90.', 'Must calculate exactly to know it''s wrong.', 'If you know the real answer has to be bigger than 90, why did they get 81? (They didn''t carry the ten).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_B', 'D9', 3, 'B', 'Checking calculations', NULL, 'Show: 83 - 28 = 65. Ask: ''Use estimation to prove if this answer is reasonable.''', 'Estimates 80 - 30 = 50. Since 65 is nowhere near 50, it is unreasonable.', 'Calculates exactly instead of estimating.', 'Why is it a good habit to estimate the answer in your head before you start doing the math on paper?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L3_C', 'D9', 3, 'C', 'Checking calculations', NULL, 'Say: ''A machine said 102 - 98 = 104. How do you know that''s crazy without calculating?''', 'Recognizes the numbers are very close together, so the difference must be tiny.', 'Cannot explain why it''s wrong conceptually.', 'When numbers are close together on the number line, is the difference big or small?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_A', 'D9', 4, 'A', 'Problem generation', NULL, 'Ask: ''Tell me a story where someone SHOULD estimate instead of counting exactly. Why is it better to estimate there?''', 'Identifies real-world situations (e.g., crowds, distant trees) where estimation is preferred or necessary.', 'Gives a situation like paying for groceries where exactness is required.', 'Can you tell me a rule for when estimation is good enough and when you NEED the exact answer?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_B', 'D9', 4, 'B', 'Problem generation', NULL, 'Ask: ''Write a math problem where estimating gives you 100, but the exact answer is 92.''', 'Creates a problem like 51 + 41.', 'Cannot reverse engineer a problem from an estimate.', 'Why does 51 + 41 estimate to 100?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_C', 'D9', 4, 'C', 'Problem generation', NULL, 'Say: ''Imagine you are building a bridge. Should you estimate how long it needs to be, or measure exactly? Why?''', 'Explains that some things must be exact because mistakes are dangerous or expensive.', 'Says estimate because it''s faster.', 'If you had to guess the cost of the bridge, would you estimate the cost higher or lower than you think? (Safety margin).', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D1_L4_M', 'D1', 4, 'M', 'Real-world situation', NULL, 'Your grandmother asks you to count the chickens on the farm. There are many. She needs to know how many there are so she can tell the vet. How would you count them so you don''t lose track and don''t have to start over?', 'Child proposes grouping by 10s or another systematic method. Reasoning: explains why grouping prevents double-counting.', 'Counts by 1s or proposes random methods.', 'Why does your method work better than just pointing at them?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D2_L4_M', 'D2', 4, 'M', 'Real-world situation', NULL, 'Your family is travelling. In the morning, you drove past 28 road signs. After lunch, you drove past 34 more. Grandmother wants to know the total so she can tell a story about it. Figure it out.', 'Child combines the quantities without being told to ''add''. Uses a strategy (make-a-ten, decomposition) and explains why the total must be more than 50.', 'Waits to be told what operation to use.', 'How did you know you needed to put those numbers together?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D3_L4_M', 'D3', 4, 'M', 'Real-world situation', NULL, 'There were 43 chapatis on the plate this morning. Now there are 17. Your aunt wants to know what happened. Help her figure it out.', 'Child recognises this is a comparison/difference situation. Finds the gap (26). Reasoning: explains that the missing chapatis are the difference between what was there and what''s left.', 'Adds the numbers together.', 'Why did you find the difference instead of adding?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D4_L4_M', 'D4', 4, 'M', 'Real-world situation', NULL, 'We are planting a garden. We have 6 rows, and each row has space for 8 seedlings. Tendo wants to buy the seedlings at the market. How many should he buy?', 'Child identifies the array/equal groups structure. Calculates 48. Does not need to be told ''multiply''.', 'Adds 6 + 8.', 'How did you know to count by 8s instead of just adding 6 and 8?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D5_L4_M', 'D5', 4, 'M', 'Real-world situation', NULL, 'Nala brought 30 groundnuts to share with her 5 friends (not including herself). She wants everyone to have the same amount. What should she do?', 'Child partitions 30 into 6 equal groups (Nala + 5 friends). Each gets 5. Reasoning: explains why 6 groups, not 5.', 'Divides by 5, forgetting Nala, or doesn''t know to divide.', 'How do you ensure everyone gets a fair share?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D6_L4_M', 'D6', 4, 'M', 'Real-world situation', NULL, 'The school is at the 15-kilometre marker on the road. The market is at the 42-kilometre marker. Your uncle wants to know how far it is from school to the market.', 'Child finds the distance (27 km) by subtraction or counting up. Reasoning: explains this is a ''how far between'' problem, not ''what is 15 plus 42''.', 'Adds 15 and 42.', 'Why does finding the space between two markers tell you the distance?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D7_L4_M', 'D7', 4, 'M', 'Real-world situation', NULL, 'You need to count the total legs on 3 tables and 7 chairs. Tables have 4 legs each and chairs have 4 legs each. Amara says you should count the table legs first, then the chair legs. Tendo says just count all the furniture and multiply by 4. Who gets the answer faster? Do they get the same answer?', 'Child recognises the distributive property/commutativity in action. Both methods work. Explains why.', 'Only calculates one way and thinks the other is wrong.', 'Why do both methods give the exact same total?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D8_L4_M', 'D8', 4, 'M', 'Real-world situation', NULL, 'Your mother gave your brother 6 sweets in the morning and 4 at lunch. She gave you some sweets at lunch only. You both have the same total. How many did she give you?', 'Child sets up the balance (6 + 4 = ?). Finds 10. Key reasoning: the child is not looking for ''= means write the answer'' — they are solving for balance.', 'Adds all numbers they hear (6+4+10).', 'How did you know you needed 10 to make it fair?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('D9_L4_M', 'D9', 4, 'M', 'Real-world situation', NULL, 'Aunt Prossy says there are about 200 people at the wedding, but Uncle Joseph says there are 500. You look at the crowd. The chairs have 10 rows of 10. Some people are standing. Who do you think is closer to right? Why?', 'Child uses the anchor (100 chairs × occupancy) to estimate. Recognises that 200 is more plausible than 500, given the visible reference point. Does NOT try to count every head.', 'Tries to guess without using the anchor information.', 'How did the rows of chairs help you prove Uncle Joseph wrong?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);

