INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_A', 'G2a', 1, 'A', 'Physical classification', 'Assorted real-world flat objects (e.g., paper, coasters, signs, cutouts)', 'Put all the items on the table. Say: ''Sort these objects into two piles: those with exactly 4 straight sides, and everything else.''', 'Child accurately sorts all quadrilaterals into one pile, regardless of shape (square, rectangle, rhombus).', 'Child puts all ''regular'' shapes in one pile, ignoring the 4-side constraint, or counts curved edges.', 'Look at this pile with 4 straight sides. Do they all look the same? Why are they in the same pile?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_B', 'G2a', 1, 'B', 'Physical classification', 'Sticks or pencils of varying lengths', 'Give the child sticks. Say: ''Build a shape with exactly 3 straight sides that are closed up tight. Now build a shape with 5 straight sides.''', 'Constructs a triangle and a pentagon. Ensures all corners meet.', 'Constructs open shapes, or uses the wrong number of sticks.', 'If you have 4 sticks, can you only make one type of shape, or many different looking ones?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L1_C', 'G2a', 1, 'C', 'Physical classification', 'Paper and scissors', 'Cut out a large triangle. Say: ''Cut one corner off this shape. Now count the sides of the new shape. How many are there?''', 'Child cuts a corner, counts the newly created edge, and realizes the new shape has 4 sides (quadrilateral).', 'Child still thinks it''s a triangle because it used to be one.', 'When you cut off one corner, what happens to the number of straight sides?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_A', 'G2a', 2, 'A', 'Property Identification', NULL, 'Show the child 5 different drawn shapes (e.g., square, irregular hexagon, triangle, circle, rhombus). Ask them to count the sides and corners of each, and name them if they can.', 'Correctly counts sides and corners for all shapes, identifying the relationship (sides = corners for polygons).', 'Miscounts sides on irregular shapes, or guesses based on appearance.', 'What do you notice about the number of sides and the number of corners on every shape with straight lines?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_B', 'G2a', 2, 'B', 'Property Identification', NULL, 'Give a description: ''I am thinking of a shape. It has exactly 4 sides. Not all sides are the same length. What shape could it be? Draw one.''', 'Draws a rectangle, trapezoid, or irregular quadrilateral.', 'Draws a square (violating the ''not all same length'' rule) or a triangle.', 'Why couldn''t the shape I''m thinking of be a square?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L2_C', 'G2a', 2, 'C', 'Property Identification', NULL, 'Say: ''Look around the room. Find 3 things that are rectangles and 1 thing that is a circle. What makes the rectangles different from the circle?''', 'Identifies correct real-world items. Articulates that rectangles have straight edges and corners, while circles are one continuous curve.', 'Picks random items, or cannot explain the difference structurally.', 'Does a rectangle always have to be lying down, or is a tall skinny door still a rectangle?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_A', 'G2a', 3, 'A', 'Error detection', NULL, 'Show a drawing of a ''square'' where one corner doesn''t quite close. Say: ''My friend says this is a square. Are they right?''', 'Identifies that it is not a polygon because it is not closed.', 'Agrees it is a square because of the general shape.', 'If an ant was walking on the lines of this shape, what would happen when it gets to the gap?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_B', 'G2a', 3, 'B', 'Error detection', NULL, 'Show a diamond (rhombus) and say: ''Someone told me this is a diamond, not a square. But if I turn my head, it looks like a square. What makes a square a square?''', 'Explains that a square must have ''L'' shaped corners (right angles), while a diamond can have squished corners.', 'Thinks any tilted square is a diamond.', 'If I take a square piece of paper and turn it, does it stop being a square?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('G2a_L3_C', 'G2a', 3, 'C', 'Error detection', NULL, 'Draw a very wide, short rectangle. Draw a tall, skinny rectangle. Say: ''A child says these are different shapes entirely. What would you tell them?''', 'Explains they are both rectangles because they both have 4 straight sides and 4 ''L'' corners.', 'Agrees they are different shapes.', 'What rules do both of these shapes follow?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);